91.4 Solve the Problem
library(dplyr)
library(tidyr)

bp_wide &lt;- read.csv("data/bp_visits_wide.csv")
baseline &lt;- read.csv("data/baseline_enrollment.csv")

bp_change &lt;- bp_wide |&gt;
  pivot_longer(cols = starts_with("sbp_visit"), names_to = "visit", names_prefix = "sbp_", values_to = "sbp") |&gt;
  filter(visit %in% c("visit1", "visit3")) |&gt;
  pivot_wider(names_from = visit, values_from = sbp) |&gt;
  filter(!is.na(visit3)) |&gt;
  mutate(change = visit3 - visit1)

bp_change_with_age &lt;- bp_change |&gt;
  left_join(baseline[, c("id", "age")], by = "id") |&gt;
  filter(!is.na(age)) |&gt;
  mutate(age_group = ifelse(age &gt;= 50, "50+", "Under 50"))

age_group_summary &lt;- bp_change_with_age |&gt;
  group_by(age_group) |&gt;
  summarise(n = n(), mean_change = round(mean(change), 2)) |&gt;
  arrange(age_group)

age_group_summary
# A tibble: 2 x 3
  age_group     n mean_change
  &lt;chr&gt;     &lt;int&gt;       &lt;dbl&gt;
1 50+           7       -1.86
2 Under 50      9       -8.56
Among the 16 participants with usable age and complete visit data, those under 50 show a much larger average blood pressure decrease (-8.56) than those 50 and older (-1.86) — the opposite of what you might have guessed, and a good reminder to report a surprising pattern rather than dismiss it, while still treating it cautiously (n=7 and n=9 are both small groups).
